        else if (fub_axi_araddr >= 32'h40000000 && fub_axi_araddr <= 32'h400FFFFF) begin
            comb_slave_select_ar[1] = 1'b1;  // scratch
        end
    end

    // Bridge ID for read channel (constant - tied to BRIDGE_ID parameter)
    assign bridge_id_ar = BRIDGE_ID_WIDTH'(BRIDGE_ID);

    // ================================================================
    // Width adaptation - Master: 128b
    // Connected to slaves with widths: [64, 128]
    // ================================================================

    // Per-width path-active gates (see comment in adapter_generator.py).
    logic aw_path_active_64b;
    assign aw_path_active_64b = comb_slave_select_aw[1];
    logic w_path_active_64b;
    assign w_path_active_64b = w_slave_select[1];
    logic ar_path_active_64b;
    assign ar_path_active_64b = comb_slave_select_ar[1];
    logic aw_path_active_128b;
    assign aw_path_active_128b = comb_slave_select_aw[0];
    logic w_path_active_128b;
    assign w_path_active_128b = w_slave_select[0];
    logic ar_path_active_128b;
    assign ar_path_active_128b = comb_slave_select_ar[0];

    // ================================================================
    // Width converter: 128b → 64b
    // ================================================================

    // Intermediate signals for 64b converter
    logic conv_64b_awready;
    logic conv_64b_wready;
    logic [3:0] conv_64b_bid;
    logic [1:0] conv_64b_bresp;
    logic conv_64b_bvalid;
    logic conv_64b_arready;
    logic [3:0] conv_64b_rid;
    logic [127:0] conv_64b_rdata;
    logic [1:0] conv_64b_rresp;
    logic conv_64b_rlast;
    logic conv_64b_rvalid;

    axi4_dwidth_converter_wr #(
        .S_AXI_DATA_WIDTH(128),
        .M_AXI_DATA_WIDTH(64),
        .AXI_ID_WIDTH(4),
        .AXI_ADDR_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .SKID_DEPTH_AW(2),
        .SKID_DEPTH_W(4),
        .SKID_DEPTH_B(2)
    ) u_wr_conv_64b (
        .aclk(aclk),
        .aresetn(aresetn),

        // Slave side (from wrapper) - BROADCAST requests; ready/B intercepted for FIFO
        .s_axi_awid(fub_axi_awid),
        .s_axi_awaddr(fub_axi_awaddr),
        .s_axi_awlen(fub_axi_awlen),
        .s_axi_awsize(fub_axi_awsize),
        .s_axi_awburst(fub_axi_awburst),
        .s_axi_awlock(fub_axi_awlock),
        .s_axi_awcache(fub_axi_awcache),
        .s_axi_awprot(fub_axi_awprot),
        .s_axi_awqos(4'b0),
        .s_axi_awregion(4'b0),
        .s_axi_awuser(1'b0),
        .s_axi_awvalid(fub_axi_awvalid && aw_path_active_64b),
        .s_axi_awready(conv_64b_awready),
        .s_axi_wdata(fub_axi_wdata),
        .s_axi_wstrb(fub_axi_wstrb),
        .s_axi_wlast(fub_axi_wlast),
        .s_axi_wuser(1'b0),
        .s_axi_wvalid(fub_axi_wvalid && w_path_active_64b),
        .s_axi_wready(conv_64b_wready),
        .s_axi_bid(conv_64b_bid),
        .s_axi_bresp(conv_64b_bresp),
        .s_axi_buser(),
        .s_axi_bvalid(conv_64b_bvalid),
        .s_axi_bready(fub_axi_bready),

        // Master side (to crossbar)
        .m_axi_awid(dma_axi4_64b_aw.id),
        .m_axi_awaddr(dma_axi4_64b_aw.addr),
        .m_axi_awlen(dma_axi4_64b_aw.len),
        .m_axi_awsize(dma_axi4_64b_aw.size),
        .m_axi_awburst(dma_axi4_64b_aw.burst),
        .m_axi_awlock(dma_axi4_64b_aw.lock),
        .m_axi_awcache(dma_axi4_64b_aw.cache),
        .m_axi_awprot(dma_axi4_64b_aw.prot),
        .m_axi_awqos(dma_axi4_64b_aw.qos),
        .m_axi_awregion(dma_axi4_64b_aw.region),
        .m_axi_awuser(dma_axi4_64b_aw.user),
        .m_axi_awvalid(dma_axi4_64b_awvalid),
        .m_axi_awready(dma_axi4_64b_awready),
        .m_axi_wdata(dma_axi4_64b_w.data),
        .m_axi_wstrb(dma_axi4_64b_w.strb),
        .m_axi_wlast(dma_axi4_64b_w.last),
        .m_axi_wuser(dma_axi4_64b_w.user),
        .m_axi_wvalid(dma_axi4_64b_wvalid),
        .m_axi_wready(dma_axi4_64b_wready),
        .m_axi_bid(dma_axi4_64b_b.id),
        .m_axi_bresp(dma_axi4_64b_b.resp),
        .m_axi_buser(dma_axi4_64b_b.user),
        .m_axi_bvalid(dma_axi4_64b_bvalid),
        .m_axi_bready(dma_axi4_64b_bready)
    );

    axi4_dwidth_converter_rd #(
        .S_AXI_DATA_WIDTH(128),
        .M_AXI_DATA_WIDTH(64),
        .AXI_ID_WIDTH(4),
        .AXI_ADDR_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .SKID_DEPTH_AR(2),
        .SKID_DEPTH_R(4)
    ) u_rd_conv_64b (
        .aclk(aclk),
        .aresetn(aresetn),

        // Slave side (from wrapper) - BROADCAST requests; arready/R intercepted for FIFO
        .s_axi_arid(fub_axi_arid),
        .s_axi_araddr(fub_axi_araddr),
        .s_axi_arlen(fub_axi_arlen),
        .s_axi_arsize(fub_axi_arsize),
        .s_axi_arburst(fub_axi_arburst),
        .s_axi_arlock(fub_axi_arlock),
        .s_axi_arcache(fub_axi_arcache),
        .s_axi_arprot(fub_axi_arprot),
        .s_axi_arqos(4'b0),
        .s_axi_arregion(4'b0),
        .s_axi_aruser(1'b0),
        .s_axi_arvalid(fub_axi_arvalid && ar_path_active_64b),
        .s_axi_arready(conv_64b_arready),
        .s_axi_rid(conv_64b_rid),
        .s_axi_rdata(conv_64b_rdata),
        .s_axi_rresp(conv_64b_rresp),
        .s_axi_rlast(conv_64b_rlast),
        .s_axi_ruser(),
        .s_axi_rvalid(conv_64b_rvalid),
        .s_axi_rready(fub_axi_rready),

        // Master side (to crossbar)
        .m_axi_arid(dma_axi4_64b_ar.id),
        .m_axi_araddr(dma_axi4_64b_ar.addr),
        .m_axi_arlen(dma_axi4_64b_ar.len),
        .m_axi_arsize(dma_axi4_64b_ar.size),
        .m_axi_arburst(dma_axi4_64b_ar.burst),
        .m_axi_arlock(dma_axi4_64b_ar.lock),
        .m_axi_arcache(dma_axi4_64b_ar.cache),
        .m_axi_arprot(dma_axi4_64b_ar.prot),
        .m_axi_arqos(dma_axi4_64b_ar.qos),
        .m_axi_arregion(dma_axi4_64b_ar.region),
        .m_axi_aruser(dma_axi4_64b_ar.user),
        .m_axi_arvalid(dma_axi4_64b_arvalid),
        .m_axi_arready(dma_axi4_64b_arready),
        .m_axi_rid(dma_axi4_64b_r.id),
        .m_axi_rdata(dma_axi4_64b_r.data),
        .m_axi_rresp(dma_axi4_64b_r.resp),
        .m_axi_rlast(dma_axi4_64b_r.last),
        .m_axi_ruser(dma_axi4_64b_r.user),
        .m_axi_rvalid(dma_axi4_64b_rvalid),
        .m_axi_rready(dma_axi4_64b_rready)
    );

    // ================================================================
    // Direct passthrough: 128b → 128b (no converter)
    // Requests: fub_axi_* → dma_axi4_128b_*
    // Responses: dma_axi4_128b_* → MUX → fub_axi_*
    // ================================================================

    // AW channel (request: fub → output)
    assign dma_axi4_128b_aw.id     = fub_axi_awid;
    assign dma_axi4_128b_aw.addr   = fub_axi_awaddr;
    assign dma_axi4_128b_aw.len    = fub_axi_awlen;
    assign dma_axi4_128b_aw.size   = fub_axi_awsize;
    assign dma_axi4_128b_aw.burst  = fub_axi_awburst;
    assign dma_axi4_128b_aw.lock   = fub_axi_awlock;
    assign dma_axi4_128b_aw.cache  = fub_axi_awcache;
    assign dma_axi4_128b_aw.prot   = fub_axi_awprot;
    assign dma_axi4_128b_aw.qos    = 4'b0;  // Tie to 0
    assign dma_axi4_128b_aw.region = 4'b0;  // Tie to 0
    assign dma_axi4_128b_aw.user   = 1'b0;  // Tie to 0
    assign dma_axi4_128b_awvalid   = fub_axi_awvalid && aw_path_active_128b;
    // awready routed via MUX

    // W channel (request: fub → output)
    assign dma_axi4_128b_w.data  = fub_axi_wdata;
    assign dma_axi4_128b_w.strb  = fub_axi_wstrb;
    assign dma_axi4_128b_w.last  = fub_axi_wlast;
    assign dma_axi4_128b_w.user  = 1'b0;  // Tie to 0
    assign dma_axi4_128b_wvalid  = fub_axi_wvalid && w_path_active_128b;
    // wready routed via MUX

    // B channel (response: output → MUX → fub)
    assign dma_axi4_128b_bready = fub_axi_bready;
    // bid, bresp, bvalid routed via MUX (user field ignored)

    // AR channel (request: fub → output)
    assign dma_axi4_128b_ar.id     = fub_axi_arid;
    assign dma_axi4_128b_ar.addr   = fub_axi_araddr;
    assign dma_axi4_128b_ar.len    = fub_axi_arlen;
    assign dma_axi4_128b_ar.size   = fub_axi_arsize;
    assign dma_axi4_128b_ar.burst  = fub_axi_arburst;
    assign dma_axi4_128b_ar.lock   = fub_axi_arlock;
    assign dma_axi4_128b_ar.cache  = fub_axi_arcache;
    assign dma_axi4_128b_ar.prot   = fub_axi_arprot;
    assign dma_axi4_128b_ar.qos    = 4'b0;  // Tie to 0
    assign dma_axi4_128b_ar.region = 4'b0;  // Tie to 0
    assign dma_axi4_128b_ar.user   = 1'b0;  // Tie to 0
    assign dma_axi4_128b_arvalid   = fub_axi_arvalid && ar_path_active_128b;
    // arready routed via MUX

    // R channel (response: output → MUX → fub)
    assign dma_axi4_128b_rready = fub_axi_rready;
    // rid, rdata, rresp, rlast, rvalid routed via MUX (user field ignored)

    // ================================================================
    // Response MUX - Route responses from width-specific paths
    // back to fub_axi_* based on address decode
    //
    // Request side (arready/awready/wready) uses the combinational
    // slave_select_{ar,aw} (valid while {ar,aw}valid is asserted).
    //
    // Response side (rvalid/rdata/..., bvalid/bid/...) cannot reuse
    // the combinational decode because fub_axi_{ar,aw}addr no longer
    // holds the request address once the {AR,AW} handshake completes
    // -- the decode reverts (typically to slave 0) and drops the
    // response. So we track slave_select_{ar,aw} per outstanding
    // request in a small FIFO captured at handshake, popped at
    // R-last / B; the FIFO head drives the response MUX.
    // ================================================================

    // OUTPUT slave_select_aw mirrors the live combinational decode.
    assign slave_select_aw = comb_slave_select_aw;

    // -------- AW->B slave_select tracking FIFO --------
    localparam int AW_TRK_DEPTH = 16;
    localparam int AW_TRK_AW    = 4;
    logic [NUM_SLAVES-1:0] aw_trk_mem [AW_TRK_DEPTH];
    logic [AW_TRK_AW:0] aw_trk_wptr, aw_trk_rptr;
    logic aw_trk_push, aw_trk_pop;

    assign aw_trk_push = fub_axi_awvalid && fub_axi_awready;
    assign aw_trk_pop  = fub_axi_bvalid && fub_axi_bready;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            aw_trk_wptr <= '0;
            aw_trk_rptr <= '0;
        end else begin
            if (aw_trk_push) begin
                aw_trk_mem[aw_trk_wptr[AW_TRK_AW-1:0]] <= comb_slave_select_aw;
                aw_trk_wptr <= aw_trk_wptr + 1'b1;
            end
            if (aw_trk_pop) begin
                aw_trk_rptr <= aw_trk_rptr + 1'b1;
            end
        end
    end

    assign b_slave_select = (aw_trk_wptr != aw_trk_rptr)
                          ? aw_trk_mem[aw_trk_rptr[AW_TRK_AW-1:0]]
                          : '0;

    // -------- AW->W slave_select tracking FIFO --------
    // Same push as AW (records slave_select at handshake);
    // pops on wlast so W#2's path-active gating doesn't wait
    // for B#1 to return. Without this, back-to-back writes
    // to different-width slaves stamp W#2's data on AW#1's
    // bucket (see multi-master 128b->32b/128b regression).
    logic [NUM_SLAVES-1:0] w_trk_mem [AW_TRK_DEPTH];
    logic [AW_TRK_AW:0] w_trk_wptr, w_trk_rptr;
    logic w_trk_push, w_trk_pop;

    assign w_trk_push = fub_axi_awvalid && fub_axi_awready;
    assign w_trk_pop  = fub_axi_wvalid && fub_axi_wready && fub_axi_wlast;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            w_trk_wptr <= '0;
            w_trk_rptr <= '0;
        end else begin
            if (w_trk_push) begin
                w_trk_mem[w_trk_wptr[AW_TRK_AW-1:0]] <= comb_slave_select_aw;
                w_trk_wptr <= w_trk_wptr + 1'b1;
            end
            if (w_trk_pop) begin
                w_trk_rptr <= w_trk_rptr + 1'b1;
            end
        end
    end

    assign w_slave_select = (w_trk_wptr != w_trk_rptr)
                          ? w_trk_mem[w_trk_rptr[AW_TRK_AW-1:0]]
                          : '0;

    // OUTPUT slave_select_ar mirrors the live combinational decode.
    assign slave_select_ar = comb_slave_select_ar;

    // -------- AR->R slave_select tracking FIFO --------
    localparam int AR_TRK_DEPTH = 16;
    localparam int AR_TRK_AW    = 4;
    logic [NUM_SLAVES-1:0] ar_trk_mem [AR_TRK_DEPTH];
    logic [AR_TRK_AW:0] ar_trk_wptr, ar_trk_rptr;
    logic ar_trk_push, ar_trk_pop;

    assign ar_trk_push = fub_axi_arvalid && fub_axi_arready;
    assign ar_trk_pop  = fub_axi_rvalid && fub_axi_rready && fub_axi_rlast;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            ar_trk_wptr <= '0;
            ar_trk_rptr <= '0;
        end else begin
            if (ar_trk_push) begin
                ar_trk_mem[ar_trk_wptr[AR_TRK_AW-1:0]] <= comb_slave_select_ar;
                ar_trk_wptr <= ar_trk_wptr + 1'b1;
            end
            if (ar_trk_pop) begin
                ar_trk_rptr <= ar_trk_rptr + 1'b1;
            end
        end
    end

    assign r_slave_select = (ar_trk_wptr != ar_trk_rptr)
                          ? ar_trk_mem[ar_trk_rptr[AR_TRK_AW-1:0]]
                          : '0;

    // AW-ready MUX (combinational comb_slave_select_aw — awaddr is live during awvalid)
    always_comb begin
        fub_axi_awready = 1'b0;
        case (comb_slave_select_aw)
            3'b010: begin  // Slave 1 (64b)
                fub_axi_awready = conv_64b_awready;
            end
            3'b001: begin  // Slave 0 (128b)
                fub_axi_awready = dma_axi4_128b_awready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // W-ready MUX (FIFO-tracked w_slave_select — awaddr has already reverted by W phase)
    always_comb begin
        fub_axi_wready = 1'b0;
        case (w_slave_select)
            3'b010: begin  // Slave 1 (64b)
                fub_axi_wready = conv_64b_wready;
            end
            3'b001: begin  // Slave 0 (128b)
                fub_axi_wready = dma_axi4_128b_wready;
            end
            default: begin
                // No active W transaction
            end
        endcase
    end

    // Write response MUX (B channel - uses b_slave_select FIFO head)
    always_comb begin
        fub_axi_bid = 4'd0;
        fub_axi_bresp = 2'b00;
        fub_axi_bvalid = 1'b0;

        case (b_slave_select)
            3'b010: begin  // Slave 1 (64b)
                fub_axi_bid = conv_64b_bid;
                fub_axi_bresp = conv_64b_bresp;
                fub_axi_bvalid = conv_64b_bvalid;
            end
            3'b001: begin  // Slave 0 (128b)
                fub_axi_bid = dma_axi4_128b_b.id;
                fub_axi_bresp = dma_axi4_128b_b.resp;
                fub_axi_bvalid = dma_axi4_128b_bvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

    // AR-ready MUX (request side: uses combinational comb_slave_select_ar)
    always_comb begin
        fub_axi_arready = 1'b0;
        case (comb_slave_select_ar)
            3'b010: begin  // Slave 1 (64b)
                fub_axi_arready = conv_64b_arready;
            end
            3'b001: begin  // Slave 0 (128b)
                fub_axi_arready = dma_axi4_128b_arready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // Read response MUX (R channel - uses r_slave_select FIFO head)
    always_comb begin
        fub_axi_rid = 4'd0;
        fub_axi_rdata = 128'd0;
        fub_axi_rresp = 2'b00;
        fub_axi_rlast = 1'b0;
        fub_axi_rvalid = 1'b0;

        case (r_slave_select)
            3'b010: begin  // Slave 1 (64b)
                fub_axi_rid = conv_64b_rid;
                fub_axi_rdata = conv_64b_rdata;
                fub_axi_rresp = conv_64b_rresp;
                fub_axi_rlast = conv_64b_rlast;
                fub_axi_rvalid = conv_64b_rvalid;
            end
            3'b001: begin  // Slave 0 (128b)
                fub_axi_rid = dma_axi4_128b_r.id;
                fub_axi_rdata = dma_axi4_128b_r.data;
                fub_axi_rresp = dma_axi4_128b_r.resp;
                fub_axi_rlast = dma_axi4_128b_r.last;
                fub_axi_rvalid = dma_axi4_128b_rvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

endmodule : dma_axi4_adapter
